INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-5ff21eeb-moex-00254', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '胎兒甲是遺腹子，其父遭乙駕車不慎撞死。下列關於胎兒甲的權利之敘述，何者正確？', '["甲尚無權利能力，不得向乙主張權利", "關於甲權利之保護，甲視為有權利能力，然而他尚未出生，無法向乙請求損害賠償", "甲得以其母為法定代理人，向乙請求損害賠償", "無論甲將來是否為死產，其胎兒期間之權利不受影響 32820、33320 33520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00255', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲公司於民國（下同）102年2月間舉辦員工旅遊，住宿乙之旅店，積欠住宿費新臺幣10萬元， 乙於103年2月催告後甲仍不給付，乙乃於104年2月訴請甲給付，於105年2月獲勝訴判決確 定。下列敘述，何者正確？', '["乙於103年2月催告時，時效中斷", "乙於104年2月訴請甲給付時，時效不完成", "判決確定後，時效重新起算5年", "判決確定後，時效重新起算15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00256', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲擁有A鑽石，出租予乙使用，乙出賣並讓與予第三人丙。下列敘述，何者錯誤？', '["倘若丙為惡意，甲仍為鑽石之所有權人", "縱使丙為惡意，甲仍不得向丙請求返還鑽石", "倘若丙為善意且無重大過失，丙取得鑽石之所有權", "倘若丙為善意且無重大過失，甲得向乙請求損害賠償或利益之返還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00257', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於民法法源之敘述，何者正確？', '["民法第1條所稱之習慣，僅指單純之習慣", "憲法總綱無法作為私法上具體請求權之基礎，故不得為法源", "法規命令非法律，故不得為法源", "法律精神演繹而出之一般法律原則，得為法源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00258', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲借給乙1千萬元，乙為避免甲強制執行其所有之A屋，乃與好友丙通謀虛偽作成買賣契約及A 屋之移轉登記。嗣後A屋被丁無權占有。下列敘述，何者錯誤？', '["乙丙間之買賣契約與物權行為均為無效", "乙得本於所有人之物上返還請求權，向丙請求塗銷所有權之登記", "甲於為保全對乙之借款返還請求權之情形下，其得以自己名義，代位乙對丙行使所有權之塗銷 登記", "丙得本於所有人之物上返還請求權，向丁請求返還A屋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00259', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '關於意思表示錯誤，下列何者為動機錯誤？', '["甲欲贈與A書給乙，而誤說為贈與B書", "甲向乙購屋，預期房屋大漲，但其後卻跌價", "甲告知秘書乙，向丙訂購A型機器，但乙口傳時誤為表示購買B型機器", "甲誤A犬為B犬向乙買受之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00260', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲向乙購買貨物一批，貨款總計新臺幣（下同）50萬元，下列情形，何者不會導致甲之50萬元 貨款債務消滅？', '["經乙之同意，甲交付等值之金塊給乙", "甲交付面額50萬元之即期支票給乙", "甲、乙同意將該買賣貨款更改為消費借貸", "甲要清償貨款債務時，因乙失蹤，甲乃向法院提存所為乙提存50萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00261', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲欲出租自己所有的A套房，於是刊登招租廣告，寫明A套房所在地點及每月租金數額，並附上 A套房內部清楚的照片。乙看到招租廣告後，立刻發電子郵件給甲表明願意依招租廣告上的條件 承租。下列關於甲乙間租賃關係是否成立之敘述，何者正確？', '["甲所為之招租廣告為要約，乙願意承租之意思表示為承諾，租賃關係成立", "甲所為之招租廣告與乙願意承租之意思表示為交錯要約，租賃關係成立", "甲所為之招租廣告為要約之引誘，乙願意承租之意思表示為要約，甲若承諾，則租賃關係成立", "甲所為之招租廣告為要約之引誘，乙願意承租之意思表示為要約，因內容一致，租賃關係成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00262', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '16歲的甲，發現鄰居乙家失火，甲雖成功撲滅火源，但於奮勇滅火之際，不慎打破乙家中的水晶 花瓶，並被火灼傷而支出醫藥費。下列關於甲乙間法律關係之敘述，何者正確？', '["甲為限制行為能力人，未經甲之法定代理人承認前，甲乙間不成立無因管理", "甲得請求乙賠償其醫藥費", "雖甲非出於重大過失，乙仍得請求甲賠償其水晶花瓶", "甲得請求乙支付其成功滅火的報酬 32820、33320 33520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00263', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲僱用無機車駕照之乙為店員，幫其送便當。乙在送便當途中機車超速撞上未戴安全帽的丙，造 成丙頭部嚴重腦震盪及全身大小挫傷。下列敘述，何者錯誤？', '["僱主甲對於丙之損害，原則上需要丙舉證甲有過失，甲始須負擔賠償責任", "雖事故之發生主要起因於乙超速，但丙未戴安全帽，亦屬與有過失", "若乙並無財產可供賠償，經丙向法院聲請，甲有可能因此一人負擔一部或全部之賠償", "甲若對丙賠償損害，事後得對乙行使求償權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
